#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
struct node 
{
    int l,r,id,idd;
    bool operator<(const node other) const
    {
    	if(idd==other.idd) return r<other.r;
    	return idd<other.idd;
	}
} b[N];
int n,q,a[N],block,ans,ans2[N],mp[N];
void add(int num)
{
	mp[num]++;
	if(mp[num]==1) ans++;
}
void erase(int num)
{
	mp[num]--;
	if(mp[num]==0) ans--;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>q;
	block=sqrt(n);
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=q;i++)
	{
		cin>>b[i].l>>b[i].r;
		b[i].id=i;
		b[i].idd=(b[i].l-1)/block;
	}
	sort(b+1,b+1+q);
	int l=1,r=1;
	add(a[1]);
	for(int i=1;i<=q;i++)
	{
		int tl=b[i].l,tr=b[i].r;
		while(l<tl)
		{
			erase(a[l]);
			l++;
		}
		while(r>tr)
		{
			erase(a[r]);
			r--;
		}
		while(l>tl)
		{
			l--;
			add(a[l]);
		}
		while(r<tr)
		{
			r++;
			add(a[r]);
		}
		ans2[b[i].id]=(bool)(ans==(b[i].r-b[i].l+1));
	}
	for(int i=1;i<=q;i++)
	{
		if(ans2[i]) cout<<"Yes\n";
		else cout<<"No\n";
	}
	return 0;
}
